/**
 * Sparkle Hostel - Database Types
 * 
 * TypeScript interfaces for all database entities
 * Note: IDs are always strings (auto-generated by Supabase)
 * Boolean fields from SQLite are returned as "0"/"1" strings
 */

// ============== ENUMS ==============

export type UserRole = 'student' | 'warden'

export type SlotStatus = 'booked' | 'waiting' | 'cancelled'

export type LaundryOrderStatus = 'pending' | 'washing' | 'ready' | 'delivered'

export type PaymentStatus = 'unpaid' | 'pending_approval' | 'paid'

export type UrgentRequestStatus = 'open' | 'fulfilled' | 'cancelled'

// ============== LAUNDRY PRICING ==============

export const LAUNDRY_PRICING: Record<string, number> = {
  'shirt': 15,
  't-shirt': 15,
  'kurta': 15,
  'top': 15,
  'pant': 15,
  'legins': 15,
  'jeans': 20,
  'saree': 20,
  'blouse': 20,
  'bedsheet': 25,
  'pillow_cover': 25,
  'blanket': 40,
  'bath_towel': 40,
} as const

export type LaundryItem = keyof typeof LAUNDRY_PRICING

export interface LaundryItemCount {
  item: LaundryItem
  count: number
}

