// ============== LAUNDRY ORDER ==============

export interface LaundryOrder {
  id: string
  userId: string
  itemsJson: string // JSON string of LaundryItemCount[]
  totalPrice: number
  status: LaundryOrderStatus
  paymentStatus: PaymentStatus
  createdAt: string
  updatedAt: string
}

// Parse items_json to get actual array
export function parseLaundryItems(itemsJson: string): LaundryItemCount[] {
  try {
    return JSON.parse(itemsJson) as LaundryItemCount[]
  } catch {
    return []
  }
}

// Create items_json from array
export function stringifyLaundryItems(items: LaundryItemCount[]): string {
  return JSON.stringify(items)
}

export interface CreateLaundryOrderInput {
  id?: string
  userId: string
  items: LaundryItemCount[]
  totalPrice?: number
  status?: LaundryOrderStatus
  paymentStatus?: PaymentStatus
}

// Calculate total price from items
export function calculateTotalPrice(items: LaundryItemCount[]): number {
  return items.reduce((total, { item, count }) => {
    const price = LAUNDRY_PRICING[item] ?? 0
    return total + (price * count)
  }, 0)
}

export interface UpdateLaundryOrderInput {
  items?: LaundryItemCount[]
  totalPrice?: number
  status?: LaundryOrderStatus
  paymentStatus?: PaymentStatus
}

